      findingProviderFieldsSeverityLabel: StringFilterList.t option
        [@ocaml.doc "The finding provider value for the severity label."];
      findingProviderFieldsSeverityOriginal: StringFilterList.t option
        [@ocaml.doc
          "The finding provider's original value for the severity."];
      findingProviderFieldsTypes: StringFilterList.t option
        [@ocaml.doc
          "One or more finding types that the finding provider assigned to the finding. Uses the format of namespace/category/classifier that classify a finding. Valid namespace values are: Software and Configuration Checks | TTPs | Effects | Unusual Behaviors | Sensitive Data Identifications"];
      sample: BooleanFilterList.t option
        [@ocaml.doc
          "Indicates whether or not sample findings are included in the filter results."]}
